                            context.EvaluatedKeywordForProperty(true, 6, RequiredPropertyOptionalValuePresent, "optionalValue"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForSchemaVersion] & RequiredBitForSchemaVersion) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 7, RequiredPropertySchemaVersionNotPresent, "schemaVersion"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 7, RequiredPropertySchemaVersionPresent, "schemaVersion"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForSignedValue] & RequiredBitForSignedValue) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 8, RequiredPropertySignedValueNotPresent, "signedValue"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 8, RequiredPropertySignedValuePresent, "signedValue"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForUnsignedValue] & RequiredBitForUnsignedValue) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 9, RequiredPropertyUnsignedValueNotPresent, "unsignedValue"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 9, RequiredPropertyUnsignedValuePresent, "unsignedValue"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForVariant] & RequiredBitForVariant) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 10, RequiredPropertyVariantNotPresent, "variant"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 10, RequiredPropertyVariantPresent, "variant"u8, "required"u8);
                        }
                    }
                }
            }

            internal static bool Evaluate(
                IJsonDocument parentDocument,
                int parentIndex,
                IJsonSchemaResultsCollector? resultsCollector = null)
            {
                JsonSchemaContext context = JsonSchemaContext.BeginContext(
                parentDocument,
                parentIndex,
                usingEvaluatedItems: false,
                usingEvaluatedProperties: true,
                resultsCollector: resultsCollector);
                try
                {
                    Evaluate(parentDocument, parentIndex, ref context);
                    context.EndContext();
                    return context.IsMatch;
                }
                finally
                {
                    context.Dispose();
                }
            }

            /// <summary>
            /// Push the current context as a child context for schema evaluation.
            /// </summary>
            /// <typeparam name="TContext">The type of the context to be passed to the path providers.</typeparam>
            /// <param name="parentDocument">The parent document of the instance for which to push the child context.</param>
            /// <param name="parentDocumentIndex">The index in the parent document of the instance for which to push the child context.</param>
            /// <param name="context">The current evaluation context.</param>
            /// <param name="providerContext">The context to be passed to the path providers.</param>
            /// <param name="schemaEvaluationPath">The (optional) path to the schema being evaluated in the child context.</param>
            /// <param name="documentEvaluationPath">The (optional) path in the document being evaluated in the child context.</param>
            /// <returns>The child context.</returns>
            internal static JsonSchemaContext PushChildContext<TContext>(
                IJsonDocument parentDocument,
                int parentDocumentIndex,
                ref JsonSchemaContext context,
                TContext providerContext,
                JsonSchemaPathProvider<TContext>? schemaEvaluationPath = null,
                JsonSchemaPathProvider<TContext>? documentEvaluationPath = null)
            {
                return
                    context.PushChildContext(
                        parentDocument,
                        parentDocumentIndex,
                        useEvaluatedItems: false,
                        useEvaluatedProperties: true,
                        evaluationPath: schemaEvaluationPath,
                        documentEvaluationPath: documentEvaluationPath,
                        providerContext: providerContext);
            }

